mapper.insert:
INSERT INTO notice_board_info (
      title
    , content
    , writer
    , view_cnt
    , notice_yn
    , delete_yn
    , created_date
    , modified_date
    , secret_yn
    , password
) VALUES (
      #{title}
    , #{content}
    , #{writer}
    , 0
    , #{noticeYn}
    , 0
    , NOW()
    , NULL
    , #{secretYn}
    , #{password}
)

mapper.update:
UPDATE notice_board_info
SET
      modified_date = NOW()
    , title = #{title}
    , content = #{content}
    , writer = #{writer}
    , notice_yn = #{noticeYn}
    , secret_yn = #{secretYn}
    , password = #{password}
WHERE
    board_id = #{boardId}

mapper.select:
SELECT
FROM notice_board_info WHERE delete_yn = 0
ORDER BY board_id DESC LIMIT #{pagination.limitStart}, #{recordSize}
